import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    { sender: "bot", text: "Hello. I’m glad you’re here. Take your time." }
  ]);

  const [input, setInput] = useState("");
  const [hasGreeted, setHasGreeted] = useState(false);

  /* ================= SONG LISTS ================= */
  const songs = {
    happy: `
🎶 Happy Mood:
• Butta Bomma – Telugu  
• Ilahi – Hindi  
• Happy – Pharrell Williams
`,
    sad: `
🎶 Gentle Comfort:
• Oopiri Aagadu – Telugu  
• Agar Tum Saath Ho – Hindi  
• Fix You – Coldplay
`,
    anxious: `
🎶 Calm & Grounding:
• Vintunnava – Telugu  
• Kun Faya Kun – Hindi  
• Weightless – Marconi Union
`,
    stressed: `
🎶 Relax & Unwind:
• Samajavaragamana – Telugu  
• Phir Le Aaya Dil – Hindi  
• Let It Be – The Beatles
`,
    angry: `
🎶 Release & Cool Down:
• Karupu Perazhaga – Telugu  
• Zinda – Hindi  
• Demons – Imagine Dragons
`
  };

  const therapistReply = (userText) => {
    const text = userText.toLowerCase().trim();

    /* ================= GREETING ================= */
    if (!hasGreeted && ["hi", "hello", "hey", "hai"].includes(text)) {
      setHasGreeted(true);
      return "Hello. I’m glad you reached out. There’s no rush—take your time.";
    }

    /* ================= HAPPY ================= */
    if (text.includes("happy") || text.includes("excited") || text.includes("great")) {
      return (
        "It sounds like you’re feeling genuinely positive today.\n\n" +
        "What do you think has contributed most to this feeling?\n\n" +
        "If you’d like, I can also share some music that matches this mood."
      );
    }

    if (text.includes("happy song") || (text.includes("song") && text.includes("happy"))) {
      return songs.happy;
    }

    /* ================= SAD ================= */
    if (text.includes("sad") || text.includes("low") || text.includes("lonely")) {
      return (
        "I’m really sorry you’re feeling this way.\n\n" +
        "Sadness can feel very heavy and isolating.\n\n" +
        "Would it help to listen to something gentle while we talk?"
      );
    }

    if (text.includes("sad song")) {
      return songs.sad;
    }

    /* ================= ANXIOUS ================= */
    if (text.includes("anxious") || text.includes("panic") || text.includes("overthinking")) {
      return (
        "That sounds exhausting.\n\n" +
        "Anxiety often makes the mind feel restless.\n\n" +
        "Before we go further, would calming music help you settle a bit?"
      );
    }

    if (text.includes("calm song") || text.includes("anxiety song")) {
      return songs.anxious;
    }

    /* ================= STRESSED ================= */
    if (text.includes("stressed") || text.includes("overwhelmed")) {
      return (
        "That sounds like a lot to handle at once.\n\n" +
        "Stress can make everything feel urgent.\n\n" +
        "Would relaxing music help you pause for a moment?"
      );
    }

    if (text.includes("stress song")) {
      return songs.stressed;
    }

    /* ================= ANGER ================= */
    if (text.includes("angry") || text.includes("frustrated") || text.includes("mad")) {
      return (
        "It sounds like there’s a lot of built-up frustration.\n\n" +
        "Anger often points to unmet needs.\n\n" +
        "Some people find music helpful to release that intensity—would you like that?"
      );
    }

    if (text.includes("angry song")) {
      return songs.angry;
    }

    /* ================= CONTEXT ================= */
    if (text.includes("exam") || text.includes("study")) {
      return "Academic pressure can be intense. What feels most stressful right now?";
    }

    if (text.includes("work")) {
      return "Work stress can drain energy over time. What’s been weighing on you?";
    }

    if (text.includes("family")) {
      return "Family matters can be emotionally complex. What’s been difficult?";
    }

    /* ================= DEFAULT ================= */
    return (
      "Thank you for sharing.\n\n" +
      "I’m here with you. Tell me more whenever you feel ready."
    );
  };

  const handleSend = () => {
    if (!input.trim()) return;

    setMessages((prev) => [
      ...prev,
      { sender: "user", text: input },
      { sender: "bot", text: therapistReply(input) }
    ]);

    setInput("");
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, i) => (
          <div key={i} className={`message-group ${msg.sender}`}>
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>{msg.text}</div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type here when you're ready..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
